inline:<div id="dna-grid-root">
  <style>
    #dna-grid-root { background: #050A0C; color: #39FF14; font-family: monospace; padding: 3rem; }
    .c3-static-grid { display: flex; flex-wrap: wrap; gap: 4px; border: 1px solid #B026FF; padding: 10px; }
    .c3-static-cell { width: 30px; text-align: center; border: 1px solid #333; }
  </style>
  <div id="dna-grid-root-static" class="c3-static-grid"></div>
  <script>
    window.c3_mount = () => {
      if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
        document.getElementById('dna-grid-root-static').innerText = "Static Sequence View: ATGC...";
      }
    };
    window.c3_destroy = () => {};
    window.c3_updateSequence = (s) => { document.getElementById('dna-grid-root-static').innerText = s; };
    window.c3_highlightBasePair = () => {};
  </script>
</div>
